 3→export const PHASE_COLORS = [
 4→  '#4A90D9', '#E07B39', '#5BAE5B', '#C75D8E',
 5→  '#8B6EC1', '#D4A843', '#44B4B4', '#D05555',
 6→];
 7→
 8→export function createPhase(name, order, color) {
 9→  return {
10→    id: generateId('phase'),
11→    name,
12→    order,
13→    color,
14→    visible: true,
15→  };
16→}
17→
18→export function createDefaultPhase() {
19→  return createPhase('Base Design', 0, PHASE_COLORS[0]);
20→}
21→
22→export function sortPhases(phases) {
23→  return [...phases].sort((a, b) => a.order - b.order);
24→}
25→
26→export function getOrderedPhases(project) {
27→  return sortPhases(project.phases || []);
28→}
29→
30→export function getNextPhaseOrder(phases) {
31→  if (!phases || phases.length === 0) return 0;
32→  return Math.max(...phases.map(p => p.order)) + 1;
33→}
34→
35→export function reorderPhases(phases, movedId, newOrder) {
36→  const sorted = sortPhases(phases);
37→  const moved = sorted.find(p => p.id === movedId);
38→  if (!moved) return sorted;
39→
40→  const others = sorted.filter(p => p.id !== movedId);
41→  const clamped = Math.max(0, Math.min(newOrder, others.length));
42→  others.splice(clamped, 0, moved);
43→
44→  return others.map((p, i) => ({ ...p, order: i }));
45→}
