209→export function createInitialEditorState(activeFloorId = null) {
210→  const modelViewport = getInitialModelViewport();
211→  const sheetViewport = getInitialSheetViewport();
212→  return {
213→    activeTool: TOOLS.SELECT,
214→    selectedId: null,
215→    selectedType: null,
216→    toolState: {},
217→    workspaceMode: 'model',
218→    viewport: { ...modelViewport },
219→    modelViewport,
220→    sheetViewport,
